241→// ── Vault guard ─────────────────────────────────────────────────────────────
242→
243→/// Middleware that blocks API requests when the vault is sealed.
244→///
245→/// Returns 423 Locked for API endpoints (except auth and gon) when the vault
246→/// is in `Sealed` state. `Uninitialized` is not blocked — the vault doesn't
247→/// exist yet and there's nothing to protect.
248→#[cfg(feature = "vault")]
249→pub async fn vault_guard(
250→    State(state): State<super::server::AppState>,
251→    request: axum::http::Request<axum::body::Body>,
252→    next: Next,
253→) -> axum::response::Response {
254→    let Some(ref vault) = state.gateway.vault else {
255→        return next.run(request).await;
256→    };
257→    let path = request.uri().path();
258→    // Allow auth, public, gon, and non-API routes through.
259→    if !path.starts_with("/api/")
260→        || path.starts_with("/api/auth/")
261→        || path.starts_with("/api/public/")
262→        || path == "/api/gon"
263→    {
264→        return next.run(request).await;
265→    }
266→    // Only block when Sealed (not Uninitialized).
267→    if matches!(vault.status().await, Ok(moltis_vault::VaultStatus::Sealed)) {
268→        return (
269→            StatusCode::LOCKED,
270→            Json(serde_json::json!({"error": "vault is sealed", "status": "sealed"})),
271→        )
272→            .into_response();
273→    }
274→    next.run(request).await
275→}
