277→// ── AuthSession extractor ───────────────────────────────────────────────────
278→
279→/// Axum extractor that validates the session cookie and produces an
280→/// `AuthIdentity`. Returns 401 if the session is missing or invalid.
281→///
282→/// When `auth_gate` has already run, it reads the [`AuthIdentity`] the
283→/// middleware inserted into extensions. For auth routes (on the public
284→/// allowlist, where `auth_gate` skips auth), it falls back to validating
285→/// the session cookie directly.
286→pub struct AuthSession(pub AuthIdentity);
287→
288→impl<S> FromRequestParts<S> for AuthSession
289→where
290→    S: Send + Sync,
291→    Arc<CredentialStore>: FromRef<S>,
292→    Arc<GatewayState>: FromRef<S>,
293→{
294→    type Rejection = (StatusCode, &'static str);
295→
296→    async fn from_request_parts(parts: &mut Parts, state: &S) -> Result<Self, Self::Rejection> {
297→        // If auth_gate already ran and set identity, use it.
298→        if let Some(id) = parts.extensions.get::<AuthIdentity>() {
299→            return Ok(AuthSession(id.clone()));
300→        }
301→
302→        // Fallback for auth routes (allowlisted, middleware skipped):
303→        // validate session cookie directly, or check the local-bypass logic.
304→        let store = Arc::<CredentialStore>::from_ref(state);
305→        let gw = Arc::<GatewayState>::from_ref(state);
306→
307→        let is_local = parts
308→            .extensions
309→            .get::<ConnectInfo<SocketAddr>>()
310→            .is_some_and(|ci| is_local_connection(&parts.headers, ci.0, gw.behind_proxy));
311→
312→        match check_auth(&store, &parts.headers, is_local).await {
313→            AuthResult::Allowed(identity) => Ok(AuthSession(identity)),
314→            _ => Err((StatusCode::UNAUTHORIZED, "not authenticated")),
315→        }
316→    }
317→}
