319→// ── Helpers ─────────────────────────────────────────────────────────────────
320→
321→/// Extract the Cookie header value.
322→fn cookie_header(headers: &HeaderMap) -> Option<&str> {
323→    headers
324→        .get(axum::http::header::COOKIE)
325→        .and_then(|v| v.to_str().ok())
326→}
327→
328→/// Extract a Bearer token from the Authorization header.
329→fn bearer_token(headers: &HeaderMap) -> Option<&str> {
