 56→function startPasskeyLogin(setError, setLoading) {
 57→	setError(null);
 58→	if (/^\d+\.\d+\.\d+\.\d+$/.test(location.hostname) || location.hostname.startsWith("[")) {
 59→		setError(t("login:passkeyRequiresDomain", { hostname: location.hostname }));
 60→		return;
 61→	}
 62→	setLoading(true);
 63→	fetch("/api/auth/passkey/auth/begin", { method: "POST" })
 64→		.then((r) => r.json())
 65→		.then((data) => {
 66→			var options = data.options;
 67→			options.publicKey.challenge = base64ToBuffer(options.publicKey.challenge);
 68→			if (options.publicKey.allowCredentials) {
 69→				for (var c of options.publicKey.allowCredentials) {
 70→					c.id = base64ToBuffer(c.id);
 71→				}
 72→			}
 73→			return navigator.credentials
 74→				.get({ publicKey: options.publicKey })
 75→				.then((cred) => ({ cred, challengeId: data.challenge_id }));
 76→		})
 77→		.then(({ cred, challengeId }) => {
 78→			var body = {
 79→				challenge_id: challengeId,
 80→				credential: {
 81→					id: cred.id,
 82→					rawId: bufferToBase64(cred.rawId),
 83→					type: cred.type,
 84→					response: {
 85→						authenticatorData: bufferToBase64(cred.response.authenticatorData),
 86→						clientDataJSON: bufferToBase64(cred.response.clientDataJSON),
 87→						signature: bufferToBase64(cred.response.signature),
 88→						userHandle: cred.response.userHandle ? bufferToBase64(cred.response.userHandle) : null,
 89→					},
 90→				},
 91→			};
 92→			return fetch("/api/auth/passkey/auth/finish", {
 93→				method: "POST",
 94→				headers: { "Content-Type": "application/json" },
 95→				body: JSON.stringify(body),
 96→			});
 97→		})
 98→		.then((r) => {
 99→			if (r.ok) {
100→				location.href = "/";
101→			} else {
102→				return r.text().then((msg) => {
103→					setError(msg || t("login:passkeyAuthFailed"));
104→					setLoading(false);
105→				});
106→			}
107→		})
108→		.catch((err) => {
109→			setError(err.message || t("login:passkeyAuthFailed"));
110→			setLoading(false);
111→		});
112→}
