169→function LoginApp() {
170→	var [password, setPassword] = useState("");
171→	var [error, setError] = useState(null);
172→	var [loading, setLoading] = useState(false);
173→	var [retrySecondsLeft, setRetrySecondsLeft] = useState(0);
174→	var [hasPasskeys, setHasPasskeys] = useState(false);
175→	var [hasPassword, setHasPassword] = useState(false);
176→	var [ready, setReady] = useState(false);
177→
178→	useEffect(() => {
179→		fetch("/api/auth/status")
180→			.then((r) => (r.ok ? r.json() : null))
181→			.then((data) => {
182→				if (!data) return;
183→				if (data.authenticated) {
184→					location.href = "/";
185→					return;
186→				}
187→				setHasPasskeys(data.has_passkeys);
188→				setHasPassword(data.has_password);
189→				setReady(true);
190→			})
191→			.catch(() => setReady(true));
192→	}, []);
193→
194→	useEffect(() => {
195→		if (retrySecondsLeft <= 0) return undefined;
196→		var timer = setInterval(() => {
197→			setRetrySecondsLeft((value) => (value > 1 ? value - 1 : 0));
198→		}, 1000);
199→		return () => clearInterval(timer);
200→	}, [retrySecondsLeft]);
201→
202→	function onPasswordLogin(e) {
203→		e.preventDefault();
204→		if (retrySecondsLeft > 0) return;
205→		setError(null);
206→		setLoading(true);
207→		fetch("/api/auth/login", {
208→			method: "POST",
209→			headers: { "Content-Type": "application/json" },
210→			body: JSON.stringify({ password }),
211→		})
212→			.then(async (r) => {
213→				if (r.ok) {
214→					location.href = "/";
215→					return;
216→				}
217→
218→				var failure = await parseLoginFailure(r);
219→				if (failure.type === "retry") {
220→					setRetrySecondsLeft(failure.retryAfter);
221→					setError(t("login:wrongPassword"));
222→				} else if (failure.type === "invalid_password") {
223→					setError(t("login:invalidPassword"));
224→				} else {
225→					setError(failure.message);
226→				}
227→				setLoading(false);
228→			})
229→			.catch((err) => {
230→				setError(err.message);
231→				setLoading(false);
232→			});
233→	}
234→
235→	function onPasskeyLogin() {
236→		startPasskeyLogin(setError, setLoading);
237→	}
238→
239→	if (!ready) {
240→		return html`<div class="auth-card">
241→			<div class="text-sm text-[var(--muted)]">${t("common:status.loading")}</div>
242→		</div>`;
243→	}
244→
245→	var title = formatLoginTitle(identity);
246→	var showPassword = hasPassword || !hasPasskeys;
247→	var showPasskeys = hasPasskeys;
248→	var showDivider = showPassword && showPasskeys;
249→
250→	return renderLoginCard({
251→		title,
252→		showPassword,
253→		showPasskeys,
254→		showDivider,
255→		password,
256→		setPassword,
257→		onPasswordLogin,
258→		onPasskeyLogin,
259→		loading,
260→		retrySecondsLeft,
261→		error,
262→	});
