            state
                .gateway_state
                .clear_passkey_host_update_pending(&host)
                .await;
            Json(serde_json::json!({ "id": id })).into_response()
        },
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()).into_response(),
    }
}

