                    .gateway_state
                    .disconnect_all_clients("last_credential_removed")
                    .await;
            }
            Json(serde_json::json!({ "ok": true })).into_response()
        },
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()).into_response(),
    }
}

