    match state
        .credential_store
        .create_api_key(body.label.trim(), body.scopes.as_deref())
        .await
    {
        Ok((id, key)) => Json(serde_json::json!({ "id": id, "key": key })).into_response(),
        Err(e) => (StatusCode::INTERNAL_SERVER_ERROR, e.to_string()).into_response(),
    }
